import React from "react"
import { Link, graphql } from "gatsby"
import Layout from "../components/Layout"
import PostExcerpt from "../components/PostExcerpt"
import Wave from "../components/Wave"
import SEO from "../components/SEO"
import "../styles/post.css"

export default function Index({ data }) {

	const qPosts = process.env.NODE_ENV === "production" ? data.qPostsProduction : data.qPostsDevelopment

	return (
		<Layout>
			<SEO />
			<div />

			<div className="content">
				<Wave />
				<div id="index-latest-posts">
					<h1>
						Latest blog posts
					</h1>
					{qPosts.nodes.map(node => (
							<PostExcerpt
								key={node.id}
								slug={node.fields.slug}
								frontmatter={node.frontmatter}
								excerpt={node.excerpt} />
					))}
					{qPosts.totalCount > 5 &&
						<div>
							<Link to="/blog">See all {qPosts.totalCount} posts</Link>
						</div>
					}
				</div>
				{/*
				<div id="index-projects">
					<h1>
						Projects
					</h1>

				</div>*/}
			</div>
		</Layout>
	)
}

export const postQuery = graphql`
	query latestPosts {
		qPostsProduction: allMdx(filter: {fields: {collection: {eq: "posts"}}, frontmatter: {draft: {ne: true}}},
							 sort: { fields: [frontmatter___date], order: DESC },
							 limit: 5) {
			nodes {
				id
				excerpt(truncate: true)
				frontmatter {
					title
					date(formatString: "YYYY.MM.DD")
					tags
				}
				fields {
					slug
				}
			}
			totalCount
		}
		qPostsDevelopment: allMdx(filter: {fields: {collection: {eq: "posts"}}},
							 sort: { fields: [frontmatter___date], order: DESC },
							 limit: 5) {
			nodes {
				id
				excerpt(truncate: true)
				frontmatter {
					title
					date(formatString: "YYYY.MM.DD")
					tags
					draft
				}
				fields {
					slug
				}
			}
			totalCount
		}
	}
`