import React from "react"
import { RandomHLine } from "react-random-shapes"
import "./Wave.css"
import { Link } from "gatsby"

export default function Wave() {

	const xWidth = 2000
	const contentWidth = 840
	const waveWidth = 10000
	const waveHeight = 1000
	const midHeight = 50
	const windowWidth = 150

	const override = new Array(17)
	for (let i = 0; i < override.length; i ++)
		override[i] = {y: ["r", 0, waveHeight]}

	override.splice(6, 5,
		{
			x: ["r", ((waveWidth-xWidth)/2)-windowWidth, ((waveWidth-xWidth)/2)+windowWidth],
			y: ["r", 0, waveHeight]
		},
		{
			x: ["r", ((waveWidth-contentWidth)/2), ((waveWidth-contentWidth)/2)+windowWidth],
			y: ["r", (waveHeight-midHeight)/2, (waveHeight+midHeight)/2]
		},
		{
			y: ["r", (waveHeight-midHeight)/2, (waveHeight+midHeight)/2]
		},
		{
			x: ["r", ((waveWidth+contentWidth)/2)-windowWidth, ((waveWidth+contentWidth)/2)],
			y: ["r", (waveHeight-midHeight)/2, (waveHeight+midHeight)/2]
		},
		{
			x: ["r", ((waveWidth+xWidth)/2)-windowWidth, ((waveWidth+xWidth)/2)+windowWidth],
			y: ["r", 0, waveHeight]
		}
	)

	const numLines = 5
	const rng = Array.from(new Array(numLines), (x, i) => i)
	const startA = Math.random() * 360
	const startB = Math.random() * 360

	const [x, setX] = React.useState(0)

	React.useEffect(() => {
		const interval = setInterval(() => {
			setX(x => Math.random())
		}, 30000)
		return () => clearInterval(interval)
	}, [])

	const stylesA = rng.map(x => {
		return {fill: "transparent", stroke: `hsl(${startA + x/numLines*360}, 100%, 30%)`, strokeWidth: Math.random()*2}
	})
	const stylesB = rng.map(x => {
		return {fill: "transparent", stroke: `hsl(${startB + x/numLines*360}, 100%, 70%)`, strokeWidth: Math.random()*2}
	})
	const styles = stylesA.concat(stylesB)
	// console.log(styles)

	return (
		<div className="hero">
			<Link to="/">
				<div className="wave-title">
					Welcome!
				</div>
			</Link>
			<div className="wave-container">
				<div className="wave">
						<RandomHLine width={waveWidth} height={waveHeight}
										 options={{numLines: numLines*2,
															 numControls: 17,
															 styleMid: styles,
														 }}
										 override={override} 
										 className={"wave-line"} misc={x}/>
				</div>
			</div>
		</div>
	)

	// return(
	// 	<div className="wave-all">
	// 		{/*<Link to="/">
	// 			<div className="wave-title">
	// 				Welcome!
	// 			</div>
	// 		</Link>*/}
	// 		<div className="full-width">
	// 			<div className="wave-container">
	// 			{
	// 				[...Array(numLines).keys()].map(i => {
	// 					return( 
	// 						<React.Fragment key={"z" + String(i)}>
	// 							<RandomHLine width={waveWidth} height={waveHeight} key={"a" + String(i)}
	// 													 options={{numControls: 17,
	// 													 					 styleMid: {fill: "transparent",
	// 													 					 						stroke: `hsl(${startA + i/numLines*360}, 100%, 30%)`,
	// 													 					 						strokeWidth: Math.random()*2},
	// 																	 }}
	// 													 override={override}
	// 													 className="wave" />
	// 							<RandomHLine width={waveWidth} height={waveHeight} key={"b" + String(i)}
	// 													 options={{numControls: 17,
	// 													 					 styleMid: {fill: "transparent",
	// 													 					 						stroke: `hsl(${startB + i/numLines*360}, 100%, 30%)`,
	// 													 					 						strokeWidth: Math.random()*2},
	// 																	 }}
	// 													 override={override}
	// 													 className="wave" />
	// 						</React.Fragment>
	// 					)
	// 				})
	// 			}
	// 			</div>
	// 		</div>
	// 	</div>
	// )

}


